from __future__ import annotations

import json
from pathlib import Path
from typing import Any

from claude_agent_sdk import create_sdk_mcp_server, tool

from gaia_bot.agent.constants import ALLOWED_MCP_TOOLS, MCP_SERVER_NAME, MCP_SERVER_VERSION
from gaia_bot.config.settings import Settings
from gaia_bot.contracts.basemodels import SearchHit, ToolTrace
from gaia_bot.services.artifacts import TaskArtifactManager


class SandboxRuntime:
    def __init__(self, settings: Settings, artifact_manager: TaskArtifactManager) -> None:
        self.settings = settings
        self.artifact_manager = artifact_manager
        self.trace: list[ToolTrace] = []
        self._executor = None

    async def __aenter__(self) -> SandboxRuntime:
        from gaia_bot.services.executor import SandboxExecutor

        self._executor = SandboxExecutor(self.settings)
        await self._executor.ensure_started()
        return self

    async def __aexit__(self, *_exc_info: object) -> None:
        if self._executor is not None:
            await self._executor.close()

    def create_mcp_server(self) -> Any:
        runtime = self

        @tool(
            "web_search",
            "Search the public web for relevant sources and return titles, urls, and snippets.",
            {
                "type": "object",
                "properties": {
                    "query": {"type": "string"},
                    "max_results": {"type": "integer", "minimum": 1, "maximum": 10},
                },
                "required": ["query"],
                "additionalProperties": False,
            },
        )
        async def web_search_tool(args: dict[str, Any]) -> dict[str, Any]:
            from gaia_bot.services.research import WebResearchClient

            query_text = args["query"]
            max_results = int(args.get("max_results", runtime.settings.max_search_results))
            research = WebResearchClient(runtime.settings)
            hits = await research.search(query_text, max_results=max_results)
            runtime._record_tool(
                "web_search",
                "research",
                args,
                _summarize_search_hits(hits),
            )
            return {
                "content": [
                    {
                        "type": "text",
                        "text": json.dumps([hit.model_dump() for hit in hits]),
                    }
                ]
            }

        @tool(
            "fetch_url",
            "Fetch and extract text from a URL, including HTML pages and PDFs.",
            {
                "type": "object",
                "properties": {
                    "url": {"type": "string"},
                    "max_chars": {"type": "integer", "minimum": 500},
                },
                "required": ["url"],
                "additionalProperties": False,
            },
        )
        async def fetch_url_tool(args: dict[str, Any]) -> dict[str, Any]:
            from gaia_bot.services.research import WebResearchClient

            research = WebResearchClient(runtime.settings)
            text = await research.fetch(args["url"], max_chars=args.get("max_chars"))
            await runtime.artifact_manager.persist_web_extract(args["url"], text)
            runtime._record_tool("fetch_url", "research", args, text[:400])
            return {"content": [{"type": "text", "text": text}]}

        @tool(
            "research_topic",
            "Search broadly, fetch top sources, and return a compact research brief.",
            {
                "type": "object",
                "properties": {
                    "query": {"type": "string"},
                    "max_results": {"type": "integer", "minimum": 1, "maximum": 5},
                },
                "required": ["query"],
                "additionalProperties": False,
            },
        )
        async def research_topic_tool(args: dict[str, Any]) -> dict[str, Any]:
            from gaia_bot.services.research import WebResearchClient

            query_text = args["query"]
            max_results = int(args.get("max_results", 3))
            research = WebResearchClient(runtime.settings)
            hits = await research.search(query_text, max_results=max_results)
            sections = []
            for hit in hits[:3]:
                extracted = await research.fetch(hit.url, max_chars=3000)
                await runtime.artifact_manager.persist_web_extract(hit.url, extracted)
                sections.append(
                    f"Title: {hit.title}\n"
                    f"URL: {hit.url}\n"
                    f"Snippet: {hit.snippet}\n"
                    f"Extract:\n{extracted[:1400]}"
                )
            summary = "\n\n---\n\n".join(sections) or "No results"
            runtime._record_tool("research_topic", "research", args, summary[:400])
            return {"content": [{"type": "text", "text": summary}]}

        @tool(
            "read_task_attachment",
            "Read and extract text from the current task attachment, if one exists.",
            {"type": "object", "properties": {}, "additionalProperties": False},
        )
        async def read_task_attachment_tool(_args: dict[str, Any]) -> dict[str, Any]:
            observation = await runtime.artifact_manager.read_task_attachment()
            if observation is None:
                runtime._record_tool(
                    "read_task_attachment",
                    "artifact",
                    {},
                    "No attachment available for this task.",
                    success=False,
                )
                return {"content": [{"type": "text", "text": "No attachment available."}]}
            text = Path(observation.stored_path).read_text()
            runtime._record_tool(
                "read_task_attachment",
                "artifact",
                {},
                observation.excerpt,
            )
            return {"content": [{"type": "text", "text": text}]}

        @tool(
            "read_local_file",
            "Read and extract text from a local file path. Use for files created during analysis.",
            {
                "type": "object",
                "properties": {"path": {"type": "string"}},
                "required": ["path"],
                "additionalProperties": False,
            },
        )
        async def read_local_file_tool(args: dict[str, Any]) -> dict[str, Any]:
            path = Path(args["path"])
            observation = await runtime.artifact_manager.read_local_path(path)
            text = Path(observation.stored_path).read_text()
            runtime._record_tool("read_local_file", "artifact", args, observation.excerpt)
            return {"content": [{"type": "text", "text": text}]}

        @tool(
            "sandbox_exec",
            (
                "Execute code inside the E2B sandbox. "
                "Use this for calculations, parsing, and reproducible transforms."
            ),
            {
                "type": "object",
                "properties": {
                    "code": {"type": "string"},
                    "language": {"type": "string"},
                    "timeout": {"type": "integer", "minimum": 1, "maximum": 300},
                },
                "required": ["code"],
                "additionalProperties": False,
            },
        )
        async def sandbox_exec_tool(args: dict[str, Any]) -> dict[str, Any]:
            assert runtime._executor is not None
            result = await runtime._executor.execute(
                args["code"],
                language=args.get("language", "python"),
                timeout=args.get("timeout"),
            )
            runtime._record_tool(
                "sandbox_exec",
                "code",
                args,
                _summarize_execution(result),
                success=result.ok,
            )
            return {"content": [{"type": "text", "text": result.model_dump_json(indent=2)}]}

        return create_sdk_mcp_server(
            name=MCP_SERVER_NAME,
            version=MCP_SERVER_VERSION,
            tools=[
                web_search_tool,
                fetch_url_tool,
                research_topic_tool,
                read_task_attachment_tool,
                read_local_file_tool,
                sandbox_exec_tool,
            ],
        )

    def _record_tool(
        self,
        name: str,
        category: str,
        arguments: dict[str, Any],
        summary: str,
        *,
        success: bool = True,
    ) -> None:
        self.trace.append(
            ToolTrace(
                name=name,
                category=category,
                arguments=arguments,
                summary=summary,
                success=success,
            )
        )


def _summarize_search_hits(hits: list[SearchHit]) -> str:
    if not hits:
        return "No results returned."
    return " | ".join(f"{hit.title}: {hit.url}" for hit in hits[:3])


def _summarize_execution(result: Any) -> str:
    pieces = []
    if result.stdout:
        pieces.append(f"stdout={result.stdout[:160]}")
    if result.stderr:
        pieces.append(f"stderr={result.stderr[:160]}")
    if result.results:
        pieces.append(f"results={result.results[0][:160]}")
    if result.error_name:
        pieces.append(f"error={result.error_name}: {result.error_value}")
    return " | ".join(pieces) or "Execution completed with no output."


__all__ = ["ALLOWED_MCP_TOOLS", "SandboxRuntime"]

from __future__ import annotations

from pathlib import Path
from typing import Any

from gaia_bot.benchmark.results import load_task_results


def compare_run_directories(base_dir: Path, candidate_dir: Path) -> dict[str, Any]:
    base = {result.task_id: result for result in load_task_results(base_dir)}
    candidate = {result.task_id: result for result in load_task_results(candidate_dir)}
    all_ids = sorted(set(base) | set(candidate))

    improved: list[str] = []
    regressed: list[str] = []
    unchanged: list[str] = []

    for task_id in all_ids:
        base_score = base.get(task_id).score if task_id in base else None
        candidate_score = candidate.get(task_id).score if task_id in candidate else None
        if base_score is None or candidate_score is None:
            unchanged.append(task_id)
        elif candidate_score > base_score:
            improved.append(task_id)
        elif candidate_score < base_score:
            regressed.append(task_id)
        else:
            unchanged.append(task_id)

    base_average = _average_score(base.values()) or 0.0
    candidate_average = _average_score(candidate.values()) or 0.0
    return {
        "base_run": base_dir.name,
        "candidate_run": candidate_dir.name,
        "base_average_score": base_average,
        "candidate_average_score": candidate_average,
        "score_delta": candidate_average - base_average,
        "improved_tasks": improved,
        "regressed_tasks": regressed,
        "unchanged_tasks": unchanged,
    }


def _average_score(results: Any) -> float | None:
    scored = [item.score for item in results if item.score is not None]
    if not scored:
        return None
    return sum(scored) / len(scored)


__all__ = ["compare_run_directories"]

from __future__ import annotations

import re
from typing import Any

from gaia_bot.contracts.basemodels import TaskRunResult

FINAL_ANSWER_RE = re.compile(r"final answer\s*:\s*(.*)", re.IGNORECASE | re.DOTALL)
SEPARATOR_RE = re.compile(r"\s*,\s*")


def extract_final_answer(text: str | None) -> str:
    if not text:
        return ""
    stripped = str(text).strip().strip("`")
    match = FINAL_ANSWER_RE.search(stripped)
    if match:
        stripped = match.group(1).strip()
    return stripped.strip().strip("`").strip()


def normalize_exact_match(answer: str | None) -> str:
    normalized = extract_final_answer(answer)
    normalized = normalized.replace("’", "'").replace("“", '"').replace("”", '"')
    normalized = re.sub(r"\s+", " ", normalized).strip().strip(".")
    normalized = SEPARATOR_RE.sub(",", normalized)
    return normalized.lower()


def infer_answer_shape(question: str) -> str:
    lowered = question.lower()
    if any(token in lowered for token in ["how many", "what is the number", "what was the total"]):
        return "number"
    if any(token in lowered for token in ["list", "comma-separated", "which of the following"]):
        return "list"
    return "short"


def format_benchmark_answer(
    answer: str | None,
    answer_shape: str = "short",
    question: str | None = None,
) -> str:
    cleaned = extract_final_answer(answer)
    cleaned = re.sub(r"\s+", " ", cleaned).strip().strip(".")

    if answer_shape == "number":
        numeric = re.search(r"[-+]?\d+(?:,\d{3})*(?:\.\d+)?", cleaned)
        if numeric:
            value = numeric.group(0).replace(",", "")
            if question and _expects_thousands_value(question):
                try:
                    thousands = float(value) / 1000
                except ValueError:
                    return value
                return _stringify_number(thousands)
            return value
        return cleaned.replace(",", "")

    if answer_shape == "list":
        parts = re.split(r"[,;\n]+", cleaned)
        normalized = [
            format_benchmark_answer(part, "short", question=question)
            for part in parts
            if part.strip()
        ]
        return ", ".join(item for item in normalized if item)

    cleaned = cleaned.strip().strip('"').strip("'").strip()
    return cleaned


def _expects_thousands_value(question: str) -> bool:
    lowered = question.lower()
    return "how many thousand" in lowered or "in thousands" in lowered


def _stringify_number(value: float) -> str:
    if value.is_integer():
        return str(int(value))
    rendered = f"{value:.6f}".rstrip("0").rstrip(".")
    return rendered


def score_prediction(predicted: str, expected: str | None) -> float | None:
    if expected is None:
        return None
    return 1.0 if normalize_exact_match(predicted) == normalize_exact_match(expected) else 0.0


def classify_failure(result: TaskRunResult) -> str | None:
    if result.score is None or result.passed:
        return None
    if any(not tool.success for tool in result.tool_calls):
        return "tool_failure"
    if result.route == "artifact" and not result.artifacts_used:
        return "parsing_miss"
    if result.route in {"web", "artifact"} and not result.solver.citations:
        return "retrieval_miss"
    if result.raw_answer and extract_final_answer(result.raw_answer) != (result.answer or ""):
        return "format_miss"
    return "wrong_answer"


def score_breakdown(results: list[TaskRunResult]) -> dict[str, Any]:
    buckets: dict[str, dict[str, int]] = {}
    tool_counts: dict[str, int] = {}
    error_counts: dict[str, int] = {}

    for result in results:
        bucket = buckets.setdefault(result.route, {"total": 0, "passed": 0})
        bucket["total"] += 1
        bucket["passed"] += int(bool(result.passed))

        if result.error_taxonomy:
            error_counts[result.error_taxonomy] = error_counts.get(result.error_taxonomy, 0) + 1

        for tool in result.tool_calls:
            tool_counts[tool.name] = tool_counts.get(tool.name, 0) + 1

    return {
        "by_route": buckets,
        "tool_counts": tool_counts,
        "error_taxonomy_counts": error_counts,
    }


__all__ = [
    "classify_failure",
    "extract_final_answer",
    "format_benchmark_answer",
    "infer_answer_shape",
    "normalize_exact_match",
    "score_breakdown",
    "score_prediction",
]

from __future__ import annotations

import os
from pathlib import Path

from pydantic import Field, SecretStr
from pydantic_settings import BaseSettings, SettingsConfigDict


class SettingsError(RuntimeError):
    """Raised when repository or environment configuration is invalid."""


def _strip_optional_quotes(value: str) -> str:
    if len(value) >= 2 and value[0] == value[-1] and value[0] in {"'", '"'}:
        return value[1:-1]
    return value


def load_dotenv_file(dotenv_path: Path) -> None:
    if not dotenv_path.exists():
        return

    for line_number, raw_line in enumerate(dotenv_path.read_text().splitlines(), start=1):
        line = raw_line.strip()
        if not line or line.startswith("#"):
            continue

        if "=" not in line:
            raise SettingsError(
                f"Malformed {dotenv_path}: line {line_number} must be KEY=value. "
                "If you pasted the raw Anthropic key, rewrite it as "
                "ANTHROPIC_API_KEY=sk-ant-...."
            )

        key, value = line.split("=", 1)
        key = key.strip()
        value = _strip_optional_quotes(value.strip())
        if not key:
            raise SettingsError(f"Malformed {dotenv_path}: line {line_number} has an empty key.")
        os.environ.setdefault(key, value)


class Settings(BaseSettings):
    model_config = SettingsConfigDict(
        env_prefix="",
        case_sensitive=True,
        extra="ignore",
    )

    anthropic_api_key: SecretStr | None = Field(default=None, alias="ANTHROPIC_API_KEY")
    e2b_api_key: SecretStr | None = Field(default=None, alias="E2B_API_KEY")
    anthropic_model_main: str = Field(
        default="claude-sonnet-4-20250514",
        alias="ANTHROPIC_MODEL_MAIN",
    )
    anthropic_model_judge: str = Field(
        default="claude-sonnet-4-20250514",
        alias="ANTHROPIC_MODEL_JUDGE",
    )
    gaia_data_path: str | None = Field(default=None, alias="GAIA_DATA_PATH")
    results_dir: Path = Field(default=Path("artifacts/results"), alias="RESULTS_DIR")
    max_turns: int = Field(default=10, alias="MAX_TURNS")
    sandbox_timeout_seconds: int = Field(default=90, alias="SANDBOX_TIMEOUT_SECONDS")
    http_timeout_seconds: int = Field(default=20, alias="HTTP_TIMEOUT_SECONDS")
    max_search_results: int = Field(default=5, alias="MAX_SEARCH_RESULTS")
    max_fetch_chars: int = Field(default=18000, alias="MAX_FETCH_CHARS")
    max_parallel_tasks: int = Field(default=3, alias="MAX_PARALLEL_TASKS")
    retry_attempts: int = Field(default=2, alias="RETRY_ATTEMPTS")
    claude_cli_path: str = Field(default="claude", alias="CLAUDE_CLI_PATH")
    working_directory: Path = Field(default=Path.cwd(), alias="WORKING_DIRECTORY")

    def require_service_credentials(
        self,
        *,
        require_anthropic: bool = True,
        require_e2b: bool = True,
    ) -> None:
        missing: list[str] = []
        if require_anthropic and self.anthropic_api_key is None:
            missing.append("ANTHROPIC_API_KEY")
        if require_e2b and self.e2b_api_key is None:
            missing.append("E2B_API_KEY")
        if missing:
            joined = ", ".join(missing)
            raise SettingsError(f"Missing required environment variables: {joined}")

    def runtime_env(self) -> dict[str, str]:
        env: dict[str, str] = {}
        if self.anthropic_api_key is not None:
            env["ANTHROPIC_API_KEY"] = self.anthropic_api_key.get_secret_value()
        if self.e2b_api_key is not None:
            env["E2B_API_KEY"] = self.e2b_api_key.get_secret_value()
        return env


def load_settings(dotenv_path: str | Path = ".env") -> Settings:
    load_dotenv_file(Path(dotenv_path))
    return Settings()


__all__ = ["Settings", "SettingsError", "load_dotenv_file", "load_settings"]

from __future__ import annotations

from gaia_bot.contracts.basemodels import PlannerDecision, SolverOutput, TaskRecord
from gaia_bot.prompts.constants import ROUTE_GUIDANCE


def route_prompt(task: TaskRecord, heuristic: PlannerDecision) -> str:
    attachment_note = ""
    if task.attachment_name or task.attachment_path:
        attachment_note = (
            f"\nAttachment detected: {task.attachment_name or task.attachment_path}\n"
            "Route this as artifact-heavy unless there is a clear reason not to."
        )
    return f"""Classify this GAIA task into one of: direct, web, code, artifact.

Task ID: {task.task_id}
Question:
{task.question}
{attachment_note}

Heuristic baseline:
- route: {heuristic.route}
- risk: {heuristic.risk}
- answer_shape: {heuristic.answer_shape}

Decide the best route, whether verifier is needed, whether web/code/artifact tools are needed,
up to 5 search queries, and a short working plan.
"""


def direct_prompt(task: TaskRecord, planner: PlannerDecision) -> str:
    return f"""Answer this low-risk GAIA task directly.

Task ID: {task.task_id}
Question:
{task.question}

Return the exact final answer only in the answer field. No explanation in the answer field.
Confidence should reflect whether the answer is trivial or certain.
"""


def solver_prompt(
    task: TaskRecord,
    planner: PlannerDecision,
    *,
    attachment_summary: str = "",
    critique: list[str] | None = None,
) -> str:
    critique_text = ""
    if critique:
        critique_text = "Fix these issues from the verifier:\n- " + "\n- ".join(critique)

    plan_lines = "\n".join(f"- {step}" for step in planner.working_plan) or "- Solve directly"
    query_lines = "\n".join(f"- {query}" for query in planner.research_queries) or "- None"
    route_guidance = ROUTE_GUIDANCE[planner.route]

    return f"""Solve this GAIA benchmark task.

Task ID: {task.task_id}
Question:
{task.question}

Route:
- route: {planner.route}
- risk: {planner.risk}
- answer_shape: {planner.answer_shape}
- needs_web: {planner.needs_web}
- needs_code: {planner.needs_code}
- needs_artifact: {planner.needs_artifact}

Working plan:
{plan_lines}

Seed queries:
{query_lines}

Attachment summary:
{attachment_summary or "None"}

Route guidance:
{route_guidance}

Benchmark constraints:
- Respect exact temporal cutoffs in the question.
- Preserve leading articles in titles and names when they are part of the answer.
- If the answer depends on counting or comparing facts, use the sandbox to verify the final value.

{critique_text}

Return the minimal benchmark-ready answer in the answer field.
Use citations for urls, files, or calculations actually used.
"""


def verifier_prompt(
    task: TaskRecord,
    planner: PlannerDecision,
    solver: SolverOutput,
) -> str:
    citations = "\n".join(f"- {item}" for item in solver.citations) or "- None"
    return f"""Review this candidate GAIA answer for benchmark scoring risk.

Task:
{task.question}

Route:
- {planner.route}
- answer_shape: {planner.answer_shape}

Candidate answer:
{solver.answer}

Reasoning summary:
{solver.reasoning_summary}

Citations:
{citations}

Decide if the answer is sufficient, grounded, and minimally formatted for exact-match scoring.
If not, list the issues and provide a revised answer that is score-ready.
"""


__all__ = ["direct_prompt", "route_prompt", "solver_prompt", "verifier_prompt"]

